import Foundation

// Struct - value type
struct Book {
    var title: String
    var author: String
    var pages: Int
}

// Class - reference type
class LibraryMember {
    let name: String
    var borrowedBooks: [Book] = []

    init(name: String) {
        self.name = name
    }

    func borrow(_ book: Book) {
        borrowedBooks.append(book)
    }
}

var book1 = Book(title: "1984", author: "Orwell", pages: 328)
var book2 = book1  // Independent copy
book2.title = "Animal Farm"
print("Book 1: \(book1.title)")  // 1984

let member = LibraryMember(name: "Alice")
member.borrow(book1)
print("\(member.name) borrowed \(member.borrowedBooks.count) book(s)")
